import axios from 'axios';
const api = axios.create({ baseURL: 'http://localhost:5000' });
export default {
  getUsers: ()=> api.get('/auth/users', { headers: { Authorization: 'Bearer '+localStorage.getItem('token') } }).then(r=>r.data),
  deleteUser: (id)=> api.delete('/auth/users/'+id, { headers: { Authorization: 'Bearer '+localStorage.getItem('token') } }).then(r=>r.data),
  getLogs: ()=> api.get('/logs/all', { headers: { Authorization: 'Bearer '+localStorage.getItem('token') } }).then(r=>r.data)
};
